import { useParams } from 'react-router-dom';

const FacilityDetails = () => {
  const { id } = useParams();

  return (
    <div className="p-4">
      <h1 className="text-3xl font-bold mb-4">Facility Details</h1>
      <p>Details for facility ID: {id}</p>
      <p>This is a placeholder page. In a real app, this would show detailed information about the facility.</p>
    </div>
  );
};

export default FacilityDetails;
